const PLUGIN_URI: &str = "http://moddevices.com/plugins/mod-devel/DS1";
const PLUGIN_DIR: &str = "mod-ds1";
pub const THUMBNAIL_PATH: Option<&str> = Some(".plugins/lv2/mod-ds1.lv2/modgui/thumbnail-ds1.png");

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "mod-ds1.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "mod-ds1.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "mod-ds1.dll";

// Port indices (from TTL)
const PORT_AUDIO_IN_IN: usize = 0;
const PORT_AUDIO_OUT_OUT1: usize = 1;
const PORT_CTRL_TONE: usize = 2;
const PORT_CTRL_LEVEL: usize = 3;
const PORT_CTRL_DIST: usize = 4;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_GAIN.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::DualMono,
        parameters: vec![
            float_parameter("tone", "Tone", None, Some(0.5), 0.01, 0.99, 0.001, ParameterUnit::None),
            float_parameter("level", "Level", None, Some(0.5), 0.01, 0.99, 0.001, ParameterUnit::None),
            float_parameter("dist", "Dist", None, Some(0.5), 0.01, 0.99, 0.001, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let tone = required_f32(params, "tone").map_err(anyhow::Error::msg)?;
    let level = required_f32(params, "level").map_err(anyhow::Error::msg)?;
    let dist = required_f32(params, "dist").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_TONE, tone),
        (PORT_CTRL_LEVEL, level),
        (PORT_CTRL_DIST, dist),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT1], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT1], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT1], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

